// Simulated async fetch function (returns after a delay)
function simulateFetch<T>(data: T, delayMs: number): Promise<T> {
  return new Promise(resolve => {
    setTimeout(() => resolve(data), delayMs);
  });
}
async function loadDashboard(): Promise<void> {
  console.time('dashboard');
  // Start both fetches at the same time (concurrent)
  const [user, products] = await Promise.all([
    simulateFetch({ name: 'Alice', role: 'admin' }, 2000),
    simulateFetch([{ id: 1, name: 'Laptop' }], 1500),
  ]);
  // Both complete in ~2s (not 3.5s) because they ran in parallel
  console.log('User:', user);
  console.log('Products:', products);
  console.timeEnd('dashboard');
}
loadDashboard();
// Expected output (timing varies):
// User: { name: 'Alice', role: 'admin' }
// Products: [ { id: 1, name: 'Laptop' } ]
// dashboard: ~2000ms
